{"action":"created","issue":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/55691","repository_url":"https://api.github.com/repos/JuliaLang/julia","labels_url":"https://api.github.com/repos/JuliaLang/julia/issues/55691/labels{/name}","comments_url":"https://api.github.com/repos/JuliaLang/julia/issues/55691/comments","events_url":"https://api.github.com/repos/JuliaLang/julia/issues/55691/events","html_url":"https://github.com/JuliaLang/julia/issues/55691","id":2506586838,"node_id":"I_kwDOABkWpM6VZ3rW","number":55691,"title":"Broadcasting not type stable (but list comprehensions & map are)","user":{"login":"kaandocal","id":26488673,"node_id":"MDQ6VXNlcjI2NDg4Njcz","avatar_url":"https://avatars.githubusercontent.com/u/26488673?v=4","gravatar_id":"","url":"https://api.github.com/users/kaandocal","html_url":"https://github.com/kaandocal","followers_url":"https://api.github.com/users/kaandocal/followers","following_url":"https://api.github.com/users/kaandocal/following{/other_user}","gists_url":"https://api.github.com/users/kaandocal/gists{/gist_id}","starred_url":"https://api.github.com/users/kaandocal/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/kaandocal/subscriptions","organizations_url":"https://api.github.com/users/kaandocal/orgs","repos_url":"https://api.github.com/users/kaandocal/repos","events_url":"https://api.github.com/users/kaandocal/events{/privacy}","received_events_url":"https://api.github.com/users/kaandocal/received_events","type":"User","site_admin":false},"labels":[{"id":115858,"node_id":"MDU6TGFiZWwxMTU4NTg=","url":"https://api.github.com/repos/JuliaLang/julia/labels/performance","name":"performance","color":"d7e102","default":false,"description":"Must go faster"},{"id":418435319,"node_id":"MDU6TGFiZWw0MTg0MzUzMTk=","url":"https://api.github.com/repos/JuliaLang/julia/labels/domain:broadcast","name":"domain:broadcast","color":"1d76db","default":false,"description":"Applying a function over a collection"}],"state":"open","locked":false,"assignee":null,"assignees":[],"milestone":null,"comments":2,"created_at":"2024-09-05T01:33:03Z","updated_at":"2024-09-05T02:43:43Z","closed_at":null,"author_association":"NONE","active_lock_reason":null,"body":"The following code (thanks @ysfoo) shows that broadcasting can fail to be type stable, even when equivalent map calls/list comprehensions are:
```julia
using LinearAlgebra

function chol_func1(mats::Vector{<:Matrix})
    return [getproperty(cholesky(mat), :L) for mat in mats]    
end
    
function chol_func2(mats::Vector{<:Matrix})
    choleskies = cholesky.(mats)
    return getproperty.(choleskies, :L) 
end

function chol_func3(mats::Vector{<:Matrix})
    choleskies = cholesky.(mats)
    return map(getproperty, choleskies, :L) 
end

bmats = [ [ 1 0; 0 1 ], [ 2 0; 0 2 ] ]

@code_warntype chol_func1(bmats)
@code_warntype chol_func2(bmats)    # NOT TYPE STABLE
@code_warntype chol_func3(bmats)
```

